namespace Kreuzberg.E2e;

/// <summary>E2e tests for category: body_limits.</summary>
public class BodyLimitsTests
{
    private static readonly JsonSerializerOptions ConfigOptions = new() { Converters = { new JsonStringEnumConverter(JsonNamingPolicy.SnakeCaseLower) }, DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingDefault };

    [Fact]
    public async Task Test_BodyOverLimitReturns413()
    {
        // Requests that exceed the configured max body size should be rejected with Payload Too Large.
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, $"{baseUrl}/fixtures/body_over_limit_returns_413");
        request.Content = new System.Net.Http.StringContent("{\"note\":\"xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx\"}", System.Text.Encoding.UTF8, "application/json");
        var response = await client.SendAsync(request);
        Assert.Equal(413, (int)response.StatusCode);
    }

    [Fact]
    public async Task Test_BodyUnderLimitSucceeds()
    {
        // Ensures requests smaller than the configured body limit are accepted.
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, $"{baseUrl}/fixtures/body_under_limit_succeeds");
        request.Content = new System.Net.Http.StringContent("{\"note\":\"small\"}", System.Text.Encoding.UTF8, "application/json");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"accepted\":true,\"note\":\"small\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }
